comments.body:
I add a patch to solve this, although it's not very elegant.
```
diff --git a/node_modules/exceljs/lib/doc/worksheet.js b/node_modules/exceljs/lib/doc/worksheet.js
index 13e4141..de937bc 100644
--- a/node_modules/exceljs/lib/doc/worksheet.js
+++ b/node_modules/exceljs/lib/doc/worksheet.js
@@ -896,7 +896,8 @@ class Worksheet {
     _.each(model.mergeCells, merge => {
       // Do not merge styles when importing an Excel file
       // since each cell may have different styles intentionally.
-      this.mergeCellsWithoutStyle(merge);
+      this.mergeCells(merge)
+      // this.mergeCellsWithoutStyle(merge);
     });
   }
 
 
```
